const msg = $('Flatten Webhook').first().json;
const aiResp = $input.first().json;
const content = msg.content || '';
const channelId = msg.channelId || msg.channel_id;

let mode = 'dev';
if (content.startsWith('$auto')) {
  mode = 'auto';
} else if (content.startsWith('$dev')) {
  mode = 'dev';
}

let task = content.replace(/^\$(ralph|team)\s*/i, '').trim();
let repository = null;

try {
  // Agent output is in .output field
  const aiText = aiResp.output || aiResp.text || '';
  const jsonMatch = aiText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.task) task = parsed.task;
    if (parsed.repository) repository = parsed.repository;
  }
} catch (e) {
  // Fallback to regex
  const repoMatch = task.match(/(\S+\/\S+)/);
  if (repoMatch) {
    repository = repoMatch[1];
    task = task.replace(repoMatch[0], '').trim();
  }
}

return {
  json: {
    mode,
    task,
    repository,
    channelId,
    author: msg.author?.username || 'unknown',
    maxRetries: mode === 'auto' ? 3 : 0
  }
};

const cmd = $('Parse Command').first().json;
const files = $input.all().map(i => i.json);

let fileTree = 'Repository structure unavailable.';
if (files.length > 0 && files[0].path) {
  fileTree = files.map(f => f.path).slice(0, 200).join('\n');
} else if (files.length > 0 && files[0].name) {
  fileTree = files.map(f => f.name).slice(0, 200).join('\n');
}

return { json: { ...cmd, fileTree } };

const cmd = $('Build Context').first().json;
const resp = $input.first().json;
const text = resp.output || resp.text || '';

let plan;
try {
  const jsonMatch = text.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  plan = JSON.parse(jsonMatch ? jsonMatch[1] : text);
} catch (e) {
  const objMatch = text.match(/\{[\s\S]*\}/);
  try {
    plan = JSON.parse(objMatch ? objMatch[0] : '{}');
  } catch {
    plan = {
      task_summary: cmd.task,
      branch_name: 'feature/auto-' + Date.now(),
      steps: [{
        step_id: 1,
        action: 'create',
        target_file: 'output.txt',
        description: text.slice(0, 500),
        acceptance_criteria: ['Implementation matches description']
      }]
    };
  }
}

const verification = plan.verification || { commands: [], expected_outcomes: [] };
const deployment = plan.deployment || null;
let steps = plan.steps || [];

if (steps.length === 0) {
  steps = [{
    step_id: 1,
    action: 'skip',
    target_file: 'README.md',
    description: 'No code changes needed — verification only',
    acceptance_criteria: ['No changes required']
  }];
}

return steps.map((step, i) => ({
  json: {
    ...cmd,
    plan_summary: plan.task_summary,
    branch_name: plan.branch_name,
    total_steps: steps.length,
    step_index: i,
    step: step,
    retryCount: 0,
    verification,
    deployment,
    skipExecution: step.action === 'skip'
  }
}));

const item = $('Loop Steps').first().json;
const fileResp = $input.first().json;

let existing = null;
let fileSha = null;
if (fileResp.content && fileResp.encoding === 'base64') {
  existing = Buffer.from(fileResp.content, 'base64').toString('utf-8');
  fileSha = fileResp.sha;
}

return {
  json: {
    ...item,
    existingContent: existing,
    fileSha
  }
};

