const prev = $('Prep for Executor').first().json;
const raw = $input.first().json;

let code = raw.output || raw.text || '';

// Strip <think>...</think> reasoning blocks
code = code.replace(/<think>[\s\S]*?<\/think>/g, '').trim();

// Strip LLM stop/special tokens
code = code.replace(/<\|im_end\|>/g, '').replace(/<\|im_start\|>/g, '').replace(/<\|endoftext\|>/g, '').trim();

// Strip markdown fences if present
code = code.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();

// If still empty, try to find code block
if (!code) {
  const match = (raw.output || '').match(/```\w*\n([\s\S]*?)\n```/);
  if (match) code = match[1].trim();
}

// Normalize step fields — handle both formats:
// Architect may return {target_file, action} or {file, name}
const step = prev.step || {};
const targetFile = step.target_file || step.file || 'output.txt';
const action = step.action || step.name || 'create';
const description = step.description || '';

return {
  json: {
    ...prev,
    step: { ...step, target_file: targetFile, action: action },
    file: targetFile,
    generatedCode: code,
    commitMsg: action + ': ' + description.slice(0, 60)
  }
};

