const results = $input.all().map(i => i.json);
const cmd = $('Parse Command').first().json;
const plan = $('Parse Plan → Split Steps').first().json;

// Check if Architect planned skip steps (verification-only run)
const isVerificationOnly = plan.skipExecution === true || plan.step?.action === 'skip';

const passed = results.filter(r => r.verdict === 'PASS').length;
const failed = results.filter(r => r.verdict === 'FAIL').length;
const total = results.length;

const verification = plan.verification || { commands: [] };
const deployment = plan.deployment || null;

let summary, createPR;
if (isVerificationOnly) {
  summary = 'Task Complete (verification only)\nNo code changes needed\nBranch: ' + plan.branch_name;
  createPR = true; // still go through verify+deploy, PR will be skipped at the end
} else {
  const stepSummary = results.map(r =>
    `${r.verdict === 'PASS' ? 'PASS' : 'FAIL'} Step ${r.step_id}: ${r.file}`
  ).join('\n');
  summary = `Task ${failed === 0 ? 'Complete' : 'Finished with Issues'} (${passed}/${total} passed)\n${stepSummary}\nBranch: ${plan.branch_name}`;
  createPR = failed === 0;
}

return {
  json: {
    repository: cmd.repository,
    branch_name: plan.branch_name,
    mode: cmd.mode,
    maxRetries: cmd.maxRetries,
    verification,
    deployment,
    retryCount: Math.max(...results.map(r => r.retryCount || 0), 0),
    summary,
    createPR,
    totalSteps: isVerificationOnly ? 0 : total,
    passedSteps: isVerificationOnly ? 0 : passed,
    verificationOnly: isVerificationOnly
  }
};

