const item = $input.first().json;
const cmds = item.verification?.commands || ['echo "No verification commands"'];
const branch = item.branch_name;
const repo = item.repository;
const jobName = 'verify-' + branch.replace(/\//g, '-').slice(0, 40) + '-' + Date.now();
const analysis = item.codebaseAnalysis || {};
const architectImage = item.verification?.container_image || '';

// Architect's image choice takes priority over analysis
const isFullStack = architectImage === 'docker:dind' || analysis.verifyMode === 'full-stack' || analysis.hasDockerCompose;
const verifyMode = isFullStack ? 'full-stack' : 'simple';

let image, fullCmd, securityContext;

if (isFullStack) {
  // MODE B: Full-stack with Docker-in-Docker
  image = 'docker:dind';
  securityContext = { privileged: true };

  const testCmd = cmds.filter(c => c !== 'echo "No verification commands"').join(' && ') || analysis.testCommand || 'echo "No test command"';

  // For full-stack: build, start, health check, then run tests inside the service container
  const healthEndpoint = item.deployment?.health_endpoint || '/';
  const port = item.deployment?.port || 8080;

  // In full-stack mode, the verification IS docker compose up + health check
  // Skip individual test commands — they'd need to run inside service containers
  const dockerTestCmds = 'echo "Full-stack verification: build + health check"';

  fullCmd = 'DOCKER_OPTS="--dns 8.8.8.8 --dns 8.8.4.4" dockerd-entrypoint.sh > /dev/null 2>&1 & ' +
    'echo "Waiting for Docker daemon..." && ' +
    'for i in $(seq 1 30); do docker info > /dev/null 2>&1 && break || sleep 1; done && ' +
    'apk add --no-cache git curl > /dev/null 2>&1 && ' +
    'git clone --branch ' + branch + ' --single-branch --depth 1 https://GITHUB_TOKEN_REDACTED@github.com/' + repo + '.git /workspace/repo && ' +
    'cd /workspace/repo && ' +
    '(docker login -u johnsoliva -p DOCKER_PAT_REDACTED > /dev/null 2>&1 || true) && ' +
    'echo "Docker ready. Building and starting services..." && ' +
    'docker compose up -d --build --wait --wait-timeout 300 2>&1 && ' +
    'echo "Services up. Running health check..." && ' +
    'for i in $(seq 1 30); do RESP=$(curl -s -o /dev/null -w "%{http_code}" http://localhost:' + port + healthEndpoint + ' 2>/dev/null); echo "Health check attempt $i: HTTP $RESP"; if [ "$RESP" = "200" ] || [ "$RESP" = "404" ] || [ "$RESP" = "301" ]; then echo "HEALTH_OK"; break; fi; sleep 2; done && ' +
    'curl -s http://localhost:' + port + healthEndpoint + ' 2>&1 | head -20 && ' +
    dockerTestCmds + ' && ' +
    'echo "VERIFICATION_PASSED" && ' +
    'docker compose logs 2>&1 | tail -50 && ' +
    'echo "Server running. Keeping alive..." && sleep infinity';

} else {
  // MODE A: Simple single container
  // Use Architect's image choice if provided, otherwise auto-detect
  if (architectImage && architectImage !== 'docker:dind') {
    image = architectImage;
  } else {
    const cmdsStr = cmds.join(' ');
    if (cmdsStr.includes('cargo') || cmdsStr.includes('rustc')) {
      image = 'rust:1.88-slim';
    } else if (cmdsStr.includes('npm') || cmdsStr.includes('node') || cmdsStr.includes('jest')) {
      image = 'node:20-slim';
    } else if (cmdsStr.includes('go test') || cmdsStr.includes('go build')) {
      image = 'golang:1.23-alpine';
    } else if (cmdsStr.includes('python') || cmdsStr.includes('pytest') || cmdsStr.includes('pip')) {
      image = 'python:3.12-slim';
    } else {
      image = 'dev-team-runner:latest';
    }
  }

  // Git install for non-runner images
  let gitInstall = '';
  if (image.includes('rust')) {
    gitInstall = 'apt-get update -qq && apt-get install -y -qq git pkg-config libssl-dev > /dev/null 2>&1 && ';
  } else if (image.includes('python') || image.includes('node')) {
    gitInstall = 'apt-get update -qq && apt-get install -y -qq git > /dev/null 2>&1 && ';
  } else if (image.includes('golang') || image.includes('alpine')) {
    gitInstall = 'apk add --no-cache git > /dev/null 2>&1 && ';
  }

  // Install deps
  let installCmd = 'true';
  if (image.includes('python') || image === 'dev-team-runner:latest') {
    installCmd = '([ -f requirements.txt ] && pip3 install --break-system-packages -q -r requirements.txt || true)';
  } else if (image.includes('node')) {
    installCmd = '([ -f package-lock.json ] && npm ci --silent || ([ -f package.json ] && npm install --silent || true))';
  } else if (image.includes('golang')) {
    installCmd = '([ -f go.mod ] && go mod download || true)';
  }

  // Fix pip commands
  const fixedCmds = cmds.map(c =>
    c.replace(/pip install(?! --break)/g, 'pip install --break-system-packages')
     .replace(/pip3 install(?! --break)/g, 'pip3 install --break-system-packages')
  );

  fullCmd = gitInstall +
    'git clone --branch ' + branch + ' --single-branch --depth 1 https://GITHUB_TOKEN_REDACTED@github.com/' + repo + '.git /workspace/repo && ' +
    'cd /workspace/repo && ' +
    installCmd + ' && ' +
    fixedCmds.join(' && ');

  securityContext = {};
}

const manifest = {
