return { json: { ...item, jobName, jobManifest: manifest, verifyImage: image, verifyMode: verifyMode, architectImage: architectImage || '(auto-detected)' } };

// Poll verify job: check job status OR pod logs for VERIFICATION_PASSED
const buildOutput = $('Build K8s Job').first().json;
const jobName = buildOutput.jobName;
const verifyMode = buildOutput.verifyMode || 'simple';
const K8S = 'https://host.docker.internal:51574';
const TOKEN = 'K8S_TOKEN_REDACTED';
const maxWait = 600;
const pollInterval = 15;

let elapsed = 0;
let jobStatus = null;
let podName = 'unknown';
let logs = 'No logs available';

while (elapsed < maxWait) {
  try {
    const jobResp = await this.helpers.httpRequest({
      method: 'GET',
      url: K8S + '/apis/batch/v1/namespaces/dev-team/jobs/' + jobName,
      headers: { 'Authorization': TOKEN },
      skipSslCertificateValidation: true,
      returnFullResponse: true,
    });
    const job = typeof jobResp.body === 'string' ? JSON.parse(jobResp.body) : jobResp.body;

    // Normal completion or failure
    if ((job.status?.succeeded || 0) >= 1 || (job.status?.failed || 0) >= 1) {
      jobStatus = job.status;
      break;
    }

    // Check running pod logs for VERIFICATION_PASSED (keep-alive mode)
    try {
      const podResp = await this.helpers.httpRequest({
        method: 'GET',
        url: K8S + '/api/v1/namespaces/dev-team/pods?labelSelector=job-name=' + jobName,
        headers: { 'Authorization': TOKEN },
        skipSslCertificateValidation: true,
        returnFullResponse: true,
      });
      const pods = typeof podResp.body === 'string' ? JSON.parse(podResp.body) : podResp.body;
      const runPod = pods.items?.find(p => p.status?.phase === 'Running');
      if (runPod) {
        podName = runPod.metadata.name;
        const logResp = await this.helpers.httpRequest({
          method: 'GET',
          url: K8S + '/api/v1/namespaces/dev-team/pods/' + podName + '/log?tailLines=60',
          headers: { 'Authorization': TOKEN },
          skipSslCertificateValidation: true,
          returnFullResponse: true,
        });
        const tail = typeof logResp.body === 'string' ? logResp.body : JSON.stringify(logResp.body);
        if (tail.indexOf('VERIFICATION_PASSED') !== -1) {
          logs = tail;
          jobStatus = { succeeded: 1 };
          break;
        }
      }
    } catch (e) {}
  } catch (e) {}

  await new Promise(resolve => setTimeout(resolve, pollInterval * 1000));
  elapsed += pollInterval;
}

if (!jobStatus) jobStatus = { failed: 1, timedOut: true };

// Read full logs
if (podName === 'unknown') {
  try {
    const podResp = await this.helpers.httpRequest({
      method: 'GET',
      url: K8S + '/api/v1/namespaces/dev-team/pods?labelSelector=job-name=' + jobName,
      headers: { 'Authorization': TOKEN },
      skipSslCertificateValidation: true,
      returnFullResponse: true,
    });
    const pods = typeof podResp.body === 'string' ? JSON.parse(podResp.body) : podResp.body;
    if (pods.items?.length > 0) podName = pods.items[0].metadata.name;
  } catch (e) {}
}
if (podName !== 'unknown' && logs === 'No logs available') {
  try {
    const logResp = await this.helpers.httpRequest({
      method: 'GET',
      url: K8S + '/api/v1/namespaces/dev-team/pods/' + podName + '/log?tailLines=200',
      headers: { 'Authorization': TOKEN },
      skipSslCertificateValidation: true,
      returnFullResponse: true,
    });
    logs = typeof logResp.body === 'string' ? logResp.body : JSON.stringify(logResp.body);
  } catch (e) {
    logs = 'Error reading logs: ' + e.message;
  }
}

return { json: { ...buildOutput, status: jobStatus, podName, verificationLogs: logs } };

const prev = $('Build K8s Job').first().json;
const pollResult = $input.first().json;

const logText = pollResult.verificationLogs || 'No logs';
const succeeded = (pollResult.status?.succeeded || 0) >= 1;
