const item = $input.first().json;
const repo = item.repository;
const jobName = 'analyze-' + repo.replace(/\//g, '-') + '-' + Date.now();
const script = "git clone --depth 1 https://GITHUB_TOKEN_REDACTED@github.com/$REPO.git /workspace/repo && cd /workspace/repo && LANG_D=unknown && FW= && DEPS= && TEST_FW= && TEST_CMD= && VERIFY_MODE=simple && HAS_COMPOSE=false && HAS_DOCKERFILE=false && SERVICES= && ENV_VARS= && HEALTH= && LANG_VERSION= && if [ -f Cargo.toml ]; then LANG_D=rust; DEPS=$(grep -E '^\\w' Cargo.toml | head -20 | tr '\\n' ', '); grep -qi actix Cargo.toml && FW=actix-web; grep -qi axum Cargo.toml && FW=axum; grep -qi rocket Cargo.toml && FW=rocket; TEST_FW=\"cargo test\"; TEST_CMD=\"cargo test\"; if [ -f rust-toolchain.toml ]; then LANG_VERSION=$(grep 'channel' rust-toolchain.toml | head -1 | sed 's/.*=[ \"]*//;s/[\"]*$//'); elif [ -f rust-toolchain ]; then LANG_VERSION=$(cat rust-toolchain | tr -d '[:space:]'); fi; if [ -z \"$LANG_VERSION\" ]; then LANG_VERSION=$(grep 'rust-version' Cargo.toml 2>/dev/null | head -1 | sed 's/.*=[ \"]*//;s/[\"]*$//'); fi; elif [ -f requirements.txt ] || [ -f pyproject.toml ]; then LANG_D=python; DEPS=$(head -20 requirements.txt 2>/dev/null | tr '\\n' ', '); grep -qi flask requirements.txt 2>/dev/null && FW=flask; grep -qi fastapi requirements.txt 2>/dev/null && FW=fastapi; grep -qi django requirements.txt 2>/dev/null && FW=django; TEST_FW=pytest; TEST_CMD=\"pytest tests/ -v\"; if [ -f .python-version ]; then LANG_VERSION=$(cat .python-version | head -1 | tr -d '[:space:]'); elif [ -f pyproject.toml ]; then LANG_VERSION=$(grep 'requires-python' pyproject.toml 2>/dev/null | head -1 | sed 's/.*>=[ \"]*//;s/[\",].*$//'); fi; elif [ -f package.json ]; then LANG_D=javascript; DEPS=$(python3 -c \"import json;d=json.load(open('package.json'));print(','.join(list(d.get('dependencies',{}).keys())[:20]))\" 2>/dev/null); grep -q react package.json && FW=react; grep -q express package.json && FW=express; grep -q next package.json && FW=nextjs; TEST_FW=jest; TEST_CMD=\"npm test\"; if [ -f .nvmrc ]; then LANG_VERSION=$(cat .nvmrc | tr -d '[:space:]' | sed 's/^v//'); elif [ -f .node-version ]; then LANG_VERSION=$(cat .node-version | tr -d '[:space:]' | sed 's/^v//'); else LANG_VERSION=$(python3 -c \"import json;d=json.load(open('package.json'));print(d.get('engines',{}).get('node',''))\" 2>/dev/null | sed 's/[>=^~ ]//g' | cut -d. -f1); fi; elif [ -f go.mod ]; then LANG_D=go; TEST_FW=\"go test\"; TEST_CMD=\"go test ./...\"; LANG_VERSION=$(grep '^go ' go.mod | awk '{print $2}'); elif [ -f Gemfile ]; then LANG_D=ruby; DEPS=$(head -20 Gemfile | tr '\\n' ', '); TEST_FW=rspec; TEST_CMD=\"bundle exec rspec\"; if [ -f .ruby-version ]; then LANG_VERSION=$(cat .ruby-version | tr -d '[:space:]'); fi; fi && if [ -f docker-compose.yml ] || [ -f docker-compose.yaml ]; then HAS_COMPOSE=true; VERIFY_MODE=full-stack; COMPOSE_FILE=$(ls docker-compose.yml docker-compose.yaml 2>/dev/null | head -1); SERVICES=$(grep \"image:\" \"$COMPOSE_FILE\" 2>/dev/null | awk '{print $2}' | tr '\\n' ', '); ENV_VARS=$(grep -E '^\\s+[A-Z_]+:' \"$COMPOSE_FILE\" 2>/dev/null | awk -F: '{print $1}' | tr -d ' ' | tr '\\n' ', ' | head -c 200); fi && if [ -f Dockerfile ]; then HAS_DOCKERFILE=true; fi && HEALTH=$(grep -rl 'health\\|healthcheck' src/ 2>/dev/null | head -1) && TEST_FILES=$(find . -maxdepth 3 \\( -name '*_test.*' -o -name 'test_*' -o -name '*.test.*' -o -name '*.spec.*' \\) 2>/dev/null | grep -v node_modules | grep -v target | head -10 | tr '\\n' ', ') && KEY_CONTENT=\"\" && for f in $(find . -maxdepth 3 \\( -name '*.py' -o -name '*.js' -o -name '*.ts' -o -name '*.go' -o -name '*.rs' \\) ! -path '*/node_modules/*' ! -path '*/target/*' ! -path '*test*' | head -5); do C=$(head -60 \"$f\" | python3 -c \"import sys,json;print(json.dumps(sys.stdin.read()))\" 2>/dev/null || echo '\"\"'); KEY_CONTENT=\"${KEY_CONTENT}\\\"$f\\\": $C,\"; done && KEY_CONTENT=\"${KEY_CONTENT%,}\" && printf '{\"language\":\"%s\",\"framework\":\"%s\",\"dependencies\":\"%s\",\"testFramework\":\"%s\",\"testCommand\":\"%s\",\"testFiles\":\"%s\",\"verifyMode\":\"%s\",\"hasDockerCompose\":%s,\"hasDockerfile\":%s,\"services\":\"%s\",\"envVars\":\"%s\",\"healthCheck\":\"%s\",\"langVersion\":\"%s\",\"keyFiles\":{%s}}' \"$LANG_D\" \"$FW\" \"$DEPS\" \"$TEST_FW\" \"$TEST_CMD\" \"$TEST_FILES\" \"$VERIFY_MODE\" \"$HAS_COMPOSE\" \"$HAS_DOCKERFILE\" \"$SERVICES\" \"$ENV_VARS\" \"$HEALTH\" \"$LANG_VERSION\" \"$KEY_CONTENT\"".replace('$REPO', repo);

const manifest = {
  apiVersion: 'batch/v1',
  kind: 'Job',
  metadata: { name: jobName, namespace: 'dev-team', labels: { app: 'dev-team-analyze' } },
  spec: {
    ttlSecondsAfterFinished: 1800,
    backoffLimit: 0,
    activeDeadlineSeconds: 120,
    template: {
      metadata: { labels: { app: 'dev-team-analyze', 'job-name': jobName } },
      spec: {
        restartPolicy: 'Never',
        containers: [{
          name: 'analyze',
          image: 'dev-team-runner:latest',
          imagePullPolicy: 'IfNotPresent',
          command: ['/bin/sh', '-c'],
          args: [script],
          resources: { limits: { cpu: '500m', memory: '512Mi' }, requests: { cpu: '250m', memory: '256Mi' } }
        }]
      }
    }
  }
};

return { json: { ...item, analysisJobName: jobName, analysisManifest: manifest } };

// Inline polling: wait for analysis job, get pod, read logs
const buildOutput = $('Build Analysis Job').first().json;
const jobName = buildOutput.analysisJobName;
const K8S = 'https://host.docker.internal:51574';
const TOKEN = 'K8S_TOKEN_REDACTED';
const maxWait = 300;
const pollInterval = 10;

let elapsed = 0;
let jobStatus = null;

while (elapsed < maxWait) {
  try {
    const jobResp = await this.helpers.httpRequest({
      method: 'GET',
      url: K8S + '/apis/batch/v1/namespaces/dev-team/jobs/' + jobName,
      headers: { 'Authorization': TOKEN },
      skipSslCertificateValidation: true,
      returnFullResponse: true,
    });
    const job = typeof jobResp.body === 'string' ? JSON.parse(jobResp.body) : jobResp.body;
    if ((job.status?.succeeded || 0) >= 1 || (job.status?.failed || 0) >= 1) {
      jobStatus = job.status;
      break;
    }
  } catch (e) {
    // Job might not be registered yet, keep polling
  }
  await new Promise(resolve => setTimeout(resolve, pollInterval * 1000));
  elapsed += pollInterval;
}

if (!jobStatus) jobStatus = { failed: 1, timedOut: true };

let podName = 'unknown';
try {
  const podResp = await this.helpers.httpRequest({
    method: 'GET',
    url: K8S + '/api/v1/namespaces/dev-team/pods?labelSelector=job-name=' + jobName,
    headers: { 'Authorization': TOKEN },
    skipSslCertificateValidation: true,
    returnFullResponse: true,
  });
  const pods = typeof podResp.body === 'string' ? JSON.parse(podResp.body) : podResp.body;
  if (pods.items && pods.items.length > 0) podName = pods.items[0].metadata.name;
} catch (e) {}

let logs = '{}';
if (podName !== 'unknown') {
  try {
    const logResp = await this.helpers.httpRequest({
      method: 'GET',
      url: K8S + '/api/v1/namespaces/dev-team/pods/' + podName + '/log?tailLines=500',
      headers: { 'Authorization': TOKEN },
      skipSslCertificateValidation: true,
      returnFullResponse: true,
    });
    logs = typeof logResp.body === 'string' ? logResp.body : JSON.stringify(logResp.body);
  } catch (e) {
    logs = '{"error": "' + e.message + '"}';
  }
}

return { json: { ...buildOutput, status: jobStatus, podName, analysisLogs: logs } };

const context = $('Build Analysis Job').first().json;
const pollResult = $input.first().json;
const logText = pollResult.analysisLogs || '{}';

let analysis = {};
try {
  const jsonMatch = logText.match(/\{[\s\S]*\}$/);
  const jsonStr = jsonMatch ? jsonMatch[0] : logText;
  analysis = JSON.parse(jsonStr);
} catch (e) {
  // JSON is malformed (unescaped quotes in dependency strings) — extract fields via regex
  const extract = (key, fallback) => {
    const m = logText.match(new RegExp('"' + key + '":"([^"]*)"'));
    return m ? m[1] : fallback;
  };
  const extractBool = (key) => {
    const m = logText.match(new RegExp('"' + key + '":(true|false)'));
    return m ? m[1] === 'true' : false;
  };

  analysis = {
    language: extract('language', 'unknown'),
    framework: extract('framework', ''),
    dependencies: extract('dependencies', ''),
    testFramework: extract('testFramework', ''),
    testCommand: extract('testCommand', ''),
    testFiles: extract('testFiles', ''),
    verifyMode: extract('verifyMode', 'simple'),
    hasDockerCompose: extractBool('hasDockerCompose'),
    hasDockerfile: extractBool('hasDockerfile'),
    services: extract('services', ''),
    envVars: extract('envVars', ''),
    healthCheck: extract('healthCheck', ''),
    langVersion: extract('langVersion', ''),
  };
}

const enrichedTree = context.fileTree +
  '\n\n--- Codebase Analysis ---' +
  '\nLanguage: ' + (analysis.language || 'unknown') +
  '\nFramework: ' + (analysis.framework || 'none') +
  '\nDependencies: ' + (analysis.dependencies || 'none') +
  '\nTest framework: ' + (analysis.testFramework || 'none') +
  '\nTest command: ' + (analysis.testCommand || 'none') +
  '\nTest files: ' + (analysis.testFiles || 'none') +
  '\nVerify mode: ' + (analysis.verifyMode || 'simple') +
  '\nDocker Compose: ' + (analysis.hasDockerCompose ? 'yes - services: ' + (analysis.services || '') : 'no') +
  '\nDockerfile: ' + (analysis.hasDockerfile ? 'yes' : 'no');

let keyFilesContext = '';
if (analysis.keyFiles) {
  for (const [path, content] of Object.entries(analysis.keyFiles)) {
    keyFilesContext += '\n\n--- ' + path + ' ---\n' + String(content).slice(0, 500);
  }
}

return {
  json: {
    ...context,
    codebaseAnalysis: analysis,
    fileTree: enrichedTree + keyFilesContext
  }
};

