const items = $input.all();
const first = items[0].json;

if (first.step_index !== 0) {
  return [];
}

// Build step list
const allSteps = items.map((it, i) =>
  `  ${i + 1}. \`${it.json.file || 'unknown'}\` — ${(it.json.action || it.json.change_description || 'modify').slice(0, 80)}`
).join('\n');

return {
  json: {
    channelId: first.channelId || $('Parse Command').first().json.channelId,
    planMessage: '**Architect Plan Ready**\n' +
      (first.plan_summary || 'Plan created') + '\n\n' +
      '**Branch:** `' + first.branch_name + '`\n' +
      '**Steps:** ' + (first.total_steps || items.length) + '\n' +
      allSteps + '\n\n' +
      'Starting Executor...'
  }
};

// Feed verification test errors back to the executor for all steps
const item = $input.first().json;
const planSteps = $('Parse Plan → Split Steps').all().map(i => i.json);

const feedback = 'VERIFICATION FAILED. The K8s test run produced these errors. Fix the code so tests pass:\n\n' +
  (item.verificationLogs || '(no logs)').slice(0, 2000);

// Re-emit all steps with the test failure feedback
return planSteps.map(stepItem => ({
  json: {
    ...stepItem,
    retryCount: item.retryCount,
    reviewerFeedback: feedback
  }
}));

const item = $input.first().json;
const dep = item.deployment;
const repo = item.repository;
const repoSlug = repo.replace(/\//g, '-').toLowerCase();
const deployName = 'deploy-' + repoSlug;
const port = dep.port || 8080;
const healthEndpoint = dep.health_endpoint || '/';

// The verify pod is already running the server — just create a Service to expose it
// The Service selector matches the verify job's pod labels
const verifyJobName = item.jobName; // from Build K8s Job

const service = {
  apiVersion: 'v1',
  kind: 'Service',
  metadata: { name: deployName, namespace: 'dev-team' },
  spec: {
    type: 'LoadBalancer',
    selector: { 'job-name': verifyJobName },
    ports: [{ port: port, targetPort: port }]
  }
};

// No deployment manifest needed — reuse the verify pod
return { json: { ...item, deployName, deployPort: port, healthEndpoint, deploymentManifest: null, serviceManifest: service } };

const item = $input.first().json;
const dep = $('Build Deploy Manifests').first().json;
const port = dep.deployPort;
const healthEndpoint = dep.healthEndpoint;

// Service was just created — Docker Desktop assigns LoadBalancer IP instantly
// Wait briefly for it to propagate
await new Promise(r => setTimeout(r, 5000));

return { json: {
  ...item,
  deployReady: true,
  deployLogs: 'Service created. Server accessible on localhost:' + port,
  deployUrl: 'http://localhost:' + port,
  healthUrl: 'http://localhost:' + port + healthEndpoint,
} };

